document.addEventListener('DOMContentLoaded', () => {
    const portfolio = document.getElementById('portfolio');
    const projects = [
        { title: 'Projeto 1', description: 'Descrição do projeto 1.', skills: ['HTML', 'CSS', 'JavaScript'] },
        { title: 'Projeto 2', description: 'Descrição do projeto 2.', skills: ['React', 'Node.js'] },
