// Sistema de Prompt

class Prompt {
  /**
   * Cria um novo prompt com uma mensagem de boas-vindas.
   */
  constructor() {
    this.mensagem = 'Bem-vindo ao sistema!';
    this.resposta = '';
    this.interativo = true;
  }

  // Método para exibir a mensagem do prompt
  showPrompt() {
    console.log(this.mensagem);
    if (this.interativo) {
      process.stdin.resume();
      process.stdin.setEncoding('utf-8');
      process.stdin.on('data', (input) => {
        this.resposta = input.trim();
        process.stdin.pause();
      });
    }
  }

  // Método para verificar se o usuário deseja sair do sistema
  exitPrompt() {
    if (this.resposta.toLowerCase() === 'sair') {
      console.log('Saindo do sistema...');
      process.exit(0);
    } else {
      this.showPrompt();
    }
  }

  // Método para exibir a mensagem de encerramento
  closePrompt() {
    console.log('Encerrando o sistema...');
    if (this.interativo) {
      process.stdin.resume();
      process.stdin.setEncoding('utf-8');
      process.stdin.on('data', () => {
        process.exit(0);
      });
    } else {
      console.log('Encerrando o sistema.');
    }
  }

  // Método para exibir a mensagem de erro
  errorPrompt(mensagem) {
    console.error(mensagem);
  }
}

const prompt = new Prompt();
prompt.showPrompt();

while (true) {
  const key = process.stdin.key();
  if (key === 's') {
    prompt.exitPrompt();
  } else if (key === 'c') {
    prompt.closePrompt();
  }
}
