// Sistema de Prompt - Versão moderna e melhorada

class Prompt {
  constructor() {
    this.mensagem = 'Bem-vindo ao sistema!';
    this.resposta = '';
    this.interativo = true;
  }

  showPrompt() {
    console.clear(); // Limpa a tela para uma experiência mais profissional
    process.stdout.write(this.mensagem + '\n');

    if (this.interativo) {
      this.registerInputListener();
    }
  }

  exitPrompt() {
    this.showPrompt();
  }

  closePrompt() {
    this.showPrompt();
  }

  errorPrompt(mensagem) {
    console.error('\x1b[31m' + mensagem + '\x1b[0m');
    this.exitPrompt();
  }

  registerInputListener() {
    process.stdin.on('keypress', (key, data) => {
      if (key === 's') {
        this.exitPrompt();
      } else if (key === 'c') {
        this.closePrompt();
      }
    });
  }
}

const prompt = new Prompt();
prompt.showPrompt();

process.stdin.resume(); // Habilita a captura de entradas do usuário
