```javascript
// Função para criar um produto e adicionar ao DOM
function createProduct(name, price) {
    const product = document.createElement('div');
    product.className = 'product';

    const title = document.createElement('h2');
    title.textContent = name;
    product.appendChild(title);

    const priceElement = document.createElement('p');
    priceElement.textContent = `Preço: R$ ${price.toFixed(2)}`;
    product.appendChild(priceElement);

    const actions = document.createElement('div');
    actions.className = 'actions';

    // Função para adicionar ao carrinho
    function addToCart() {
        alert(`Produto "${name}" adicionado ao carrinho.`);
    }

    // Adiciona o botão de adicionar ao carrinho
    const addButton = document.createElement('button');
    addButton.textContent = 'Adicionar ao Carrinho';
    addButton.classList.add('btn-add-to-cart');
    addButton.addEventListener('click', addToCart);
    actions.appendChild(addButton);

    product.appendChild(actions);

    return product;
}

// Adiciona produtos à página
window.addEventListener('DOMContentLoaded', function() {
    const content = document.querySelector('.content');
    if (!content) return;

    const productsData = [
        { name: "Produto 1", price: 29.99 },
        { name: "Produto 2", price: 49.99 },
        { name: "Produto 3", price: 79.99 }
    ];

    productsData.forEach(prod => {
        const productElem = createProduct(prod.name, prod.price);
        content.appendChild(productElem);

        // Adiciona estilo para o produto
        productElem.classList.add('product-style');

        // Adiciona estilo para o botão de adicionar ao carrinho
        addButton.classList.add('btn-add-to-cart-style');
    });

    const styles = document.createElement('style');
    styles.textContent = `
        .content {
            display: flex;
            flex-wrap: wrap;
            justify-content: center;
        }

        .product {
            width: 250px;
            margin: 20px;
            padding: 10px;
            border: 1px solid #ddd;
            border-radius: 10px;
            box-shadow: 0 0 10px rgba(0, 0, 0, 0.1);
        }

        .product-style {
            background-color: #f2f2f2;
        }

        .actions {
            display: flex;
            justify-content: space-between;
            margin-top: 20px;
        }

        .btn-add-to-cart {
            padding: 10px 20px;
            border: none;
            border-radius: 5px;
            background-color: #4CAF50;
            color: #fff;
            cursor: pointer;
        }

        .btn-add-to-cart-style {
            background-color: #34C759;
        }
    `;
    document.head.appendChild(styles);

    // Função para exibir o total
    function displayTotal(products) {
        const total = products.reduce((acc, product) => acc + product.price, 0);
        alert(`Total: R$ ${total.toFixed(2)}`);
    }

    displayTotal(productsData);
});
