                document.getElementById('modal').style.display = 'block';
            }

            function closeModal() {
                document.getElementById('modal').style.display = 'none';
            }

            window.onclick = function(event) {
                if (event.target == document.getElementById('modal')) {
                    closeModal();
                }
            }

            // Scroll suave para os itens da seção Produtos
            const itemsToScroll = document.querySelectorAll('.card');
            itemsToScroll.forEach(item => {
                item.addEventListener('click', () => {
                    window.scrollTo({
                        top: item.offsetTop - 100, 
                        behavior: 'smooth'
                    });
                });
            });

            // Tratamento do formulário de inscrição
            const inscricaoForm = document.getElementById('inscricao-form');
            inscricaoForm.addEventListener('submit', (e) => {
                e.preventDefault();
                console.log('Formulário enviado:', new FormData(inscricaoForm));
            });
        </script>
