      text-align: center;
      margin-bottom: 30px;
    }

    .jogo-container form {
      display: flex;
      flex-direction: column;
      gap: 20px;
    }

    .jogo-container label {
      font-weight: bold;
    }

    .jogo-container input[type="number"] {
      padding: 10px;
      border-radius: 5px;
      border: 1px solid #ccc;
      box-sizing: border-box;
    }

    .jogo-container button {
      background-color: #3498db;
      color: #fff;
      border: none;
      padding: 10px 20px;
      border-radius: 5px;
      font-weight: bold;
      cursor: pointer;
      transition: background-color 0.3s ease;
    }

    .jogo-container button:hover {
      background-color: #2980b9;
    }

    @media (max-width: 768px) {
      .jogo-container form {
        flex-direction: column;
        align-items: center;
      }
    }
  </style>
</head>
