<div class="jogo-container">
  <h1>Joguinho - Jovem e Sério</h1>
  <form id="jogo-form">
    <label for="idade">Qual é a sua idade?</label>
    <input type="number" id="idade" name="idade" required>

    <button type="submit">Jogar</button>
  </form>

<script>
  document.getElementById('jogo-form').addEventListener('submit', function(e) {
    e.preventDefault();

    const idade = document.getElementById('idade').value;

    if (idade >= 18) {
      alert('Parabéns! Você está apto para jogar.');
    } else {
      alert('Desculpe, você não está apto para jogar ainda. Fique por dentro da próxima!');
    }
  });
</script>
</div>

</body>
</html>
